import { Request, Response } from 'express';
import { GroupService } from './group.service';
import { createGroupValidator, linkTelegramValidator } from './group.validator';
import { AppError } from '../../middlewares/error-handler';
import { logger } from '../../middlewares/logger';

export class GroupController {
  constructor(private groupService: GroupService) {}

  async createGroup(req: Request, res: Response): Promise<Response> {
    try {
      const validatedInput = createGroupValidator.parse(req.body);
      const group = await this.groupService.createGroup(validatedInput, req.user.id);
      return res.status(201).json({ success: true, data: group });
    } catch (error) {
      logger.error({
        message: 'Failed to create group',
        error,
        requestId: req.id,
        userId: req.user.id,
      });
      if (error instanceof AppError) {
        return res.status(error.statusCode).json({ success: false, error: error.message });
      }
      return res.status(500).json({ success: false, error: 'Internal Server Error' });
    }
  }

  async getGroupById(req: Request, res: Response): Promise<Response> {
    try {
      const group = await this.groupService.getGroupById(req.params.id);
      return res.status(200).json({ success: true, data: group });
    } catch (error) {
      logger.error({
        message: 'Failed to get group',
        error,
        requestId: req.id,
        userId: req.user.id,
      });
      if (error instanceof AppError) {
        return res.status(error.statusCode).json({ success: false, error: error.message });
      }
      return res.status(500).json({ success: false, error: 'Internal Server Error' });
    }
  }

  async linkTelegram(req: Request, res: Response): Promise<Response> {
    try {
      const validatedInput = linkTelegramValidator.parse(req.body);
      const group = await this.groupService.linkTelegram(req.params.id, validatedInput.telegramChatId);
      return res.status(200).json({ success: true, data: group });
    } catch (error) {
      logger.error({
        message: 'Failed to link telegram',
        error,
        requestId: req.id,
        userId: req.user.id,
      });
      if (error instanceof AppError) {
        return res.status(error.statusCode).json({ success: false, error: error.message });
      }
      return res.status(500).json({ success: false, error: 'Internal Server Error' });
    }
  }
}

import { GroupRepository } from './group.repository';
import { GroupDTO, CreateGroupDTO } from './group.dto';
import { AppError } from '../../middlewares/error-handler';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  async createGroup(data: CreateGroupDTO, adminId: string): Promise<GroupDTO> {
    if (!await this.groupRepository.isAdmin(adminId)) {
      throw new AppError('Unauthorized access', 403, 'UNAUTHORIZED');
    }
    const group = await this.groupRepository.create(data, adminId);
    return new GroupDTO(group);
  }

  async getGroupById(id: string): Promise<GroupDTO> {
    const group = await this.groupRepository.findById(id);
    if (!group) {
      throw new AppError('Group not found', 404, 'NOT_FOUND');
    }
    return new GroupDTO(group);
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<GroupDTO> {
    const group = await this.groupRepository.linkTelegram(groupId, telegramChatId);
    if (!group) {
      throw new AppError('Group not found', 404, 'NOT_FOUND');
    }
    return new GroupDTO(group);
  }
}

import { Group } from './group.model';
import { model, ObjectId } from 'mongoose';
import { CreateGroupDTO } from './group.dto';

export class GroupRepository {
  private GroupModel = model<Group>('Group');

  async create(data: CreateGroupDTO, adminId: string): Promise<Group> {
    const group = await this.GroupModel.create({ ...data, adminId });
    return group;
  }

  async findById(id: string): Promise<Group | null> {
    return this.GroupModel.findById(id).populate('members').exec();
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<Group | null> {
    return this.GroupModel.findByIdAndUpdate(groupId, { telegramChatId }, { new: true }).exec();
  }

  async isAdmin(userId: string): Promise<boolean> {
    // This is a dummy check, replace with actual role check logic.
    const group = await this.GroupModel.findOne({ adminId: new ObjectId(userId) });
    return group !== null;
  }
}

import { z } from 'zod';

export const createGroupValidator = z.object({
  name: z.string().min(1, 'Group name is required'),
  description: z.string().optional(),
});

export const linkTelegramValidator = z.object({
  telegramChatId: z.string().min(1, 'Telegram Chat ID is required'),
});

import { ObjectId } from 'mongodb';

export class CreateGroupDTO {
  name: string;
  description?: string;
  adminId: ObjectId;

  constructor(name: string, description: string | undefined, adminId: ObjectId) {
    this.name = name;
    this.description = description;
    this.adminId = adminId;
  }
}

export class GroupDTO {
  id: string;
  name: string;
  description?: string;
  adminId: string;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;

  constructor(group: any) {
    this.id = group.id.toString();
    this.name = group.name;
    this.description = group.description;
    this.adminId = group.adminId.toString();
    this.members = group.members;
    this.telegramChatId = group.telegramChatId;
    this.createdAt = group.createdAt;
  }
}
